using System.Net;using System.Net.Http.Json;using System.Text.Json;using DBH.UnitTest.Shared;namespace DBH.UnitTest.UnitTests;/// <summary>/// Good case: Grant consent with valid patient and grantee IDs/// Expected: 201 Created/// </summary>public class ConsentServiceTests_GrantConsent_WithValidUsers_ShouldCreateConsent : ApiTestBase{    protected override IReadOnlyCollection<string> RequiredServices => new[]    {        "AuthService",        "ConsentService"    };    [SkippableFact]    public async Task GrantConsent_WithValidUsers_ShouldCreateConsent()    {        await AuthenticateAsPatientAsync(ConsentClient);        var request = new         {             patientDid = TestSeedData.PatientUserId.ToString(),             granteeDid = TestSeedData.DoctorUserId.ToString(),             scope = "read"         };        var response = await PostAsJsonWithRetryAsync(ConsentClient, ApiEndpoints.Consents.Grant, request);        Assert.True(            response.StatusCode == HttpStatusCode.Created ||             response.StatusCode == HttpStatusCode.OK,            $"Expected 201 or 200, got {response.StatusCode}");    }}